const projects = $input.all().map(i => i.json);
const now = new Date();
const todayStr = now.toISOString().split('T')[0];

const isEvening = now.getUTCHours() >= 9; // 09:30 UTC = 16:30 WIB
const sessionLabel = isEvening ? '🌆 REMINDER SORE' : '🌅 REMINDER PAGI';

function getProp(props, key, type) {
  const p = props?.[key];
  if (!p) return null;
  if (type === 'title') return p.title?.[0]?.plain_text || null;
  if (type === 'text') return p.rich_text?.[0]?.plain_text || null;
  if (type === 'select') return p.select?.name || null;
  if (type === 'multi_select') return (p.multi_select || []).map(s => s.name);
  if (type === 'date') return p.date?.start || null;
  return null;
}

const phaseDateMap = {
  'Pre-Kickoff': 'date_pre_kickoff',
  'Kickoff': 'date_kickoff',
  'Initial Test': 'date_initial_test',
  'Initial Report': 'date_initial_report',
  'Presentation': 'date_presentation',
  'Patching': 'date_patching',
  'Retest': 'date_retest',
  'Retest Report': 'date_retest_report'
};

function calcDaysUntil(dateStr) {
  if (!dateStr) return null;
  const target = new Date(dateStr);
  const diff = target - now;
  return Math.ceil(diff / (1000 * 60 * 60 * 24));
}

function calcStatus(props) {
  const currentPhase = getProp(props, 'current_phase', 'select');
  if (!currentPhase || currentPhase === 'Pre-Kickoff') return 'Pre-Engagement';
  const dateField = phaseDateMap[currentPhase];
  if (dateField) {
    const d = getProp(props, dateField, 'date');
    if (d && now > new Date(d)) return 'Delay';
  }
  if (currentPhase === 'Retest Report') {
    const d = getProp(props, 'date_retest_report', 'date');
    if (d && now > new Date(d)) return 'Finish';
  }
  return 'On Going';
}

const activeProjects = projects.filter(p => {
  const status = calcStatus(p.properties);
  return status !== 'Finish';
});

const reminderLines = [`${sessionLabel} — ${new Date().toLocaleDateString('id-ID', { timeZone: 'Asia/Jakarta', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })} WIB`, ''];

let hasUrgent = false;

activeProjects.forEach(p => {
  const props = p.properties;
  const projectId = getProp(props, 'project_id', 'title') || 'N/A';
  const projectName = getProp(props, 'project_name', 'text') || 'N/A';
  const currentPhase = getProp(props, 'current_phase', 'select') || 'N/A';
  const status = calcStatus(props);
  const pmNotes = getProp(props, 'pm_notes', 'text');
  const lastUpdated = getProp(props, 'last_updated', 'date');
  const dateField = phaseDateMap[currentPhase];
  const phaseDate = dateField ? getProp(props, dateField, 'date') : null;
  const daysUntil = calcDaysUntil(phaseDate);

  let statusEmoji = '🟢';
  let alertLines = [];

  if (status === 'Delay') {
    statusEmoji = '🔴';
    alertLines.push(`⚠️ TERLAMBAT — Fase ${currentPhase} sudah lewat dari jadwal!`);
    hasUrgent = true;
  } else if (daysUntil !== null && daysUntil <= 3 && daysUntil >= 0) {
    statusEmoji = '🟡';
    alertLines.push(`🔔 Fase <b>${currentPhase}</b> berakhir dalam <b>${daysUntil} hari</b> (${phaseDate})`);
    hasUrgent = true;
  }

  // Check if PM notes need update (> 24 hours without update)
  if (lastUpdated) {
    const lastUpdate = new Date(lastUpdated);
    const hoursSinceUpdate = (now - lastUpdate) / (1000 * 60 * 60);
    if (hoursSinceUpdate > 24) {
      alertLines.push(`📝 Catatan PM belum diupdate lebih dari 24 jam`);
    }
  } else {
    alertLines.push(`📝 Belum ada catatan PM untuk proyek ini`);
  }

  reminderLines.push(`${statusEmoji} <b>${projectId}</b> — ${projectName}`);
  reminderLines.push(`   📍 Fase: ${currentPhase} | Status: ${status}`);
  if (phaseDate) reminderLines.push(`   📅 Target: ${phaseDate}${daysUntil !== null ? ` (${daysUntil >= 0 ? daysUntil + ' hari lagi' : Math.abs(daysUntil) + ' hari lewat'})` : ''}`);
  alertLines.forEach(a => reminderLines.push(`   ${a}`));
  reminderLines.push('');
});

if (activeProjects.length === 0) {
  reminderLines.push('✅ Tidak ada proyek aktif saat ini.');
}

if (hasUrgent) {
  reminderLines.unshift('🚨 <b>ADA ITEM YANG MEMBUTUHKAN PERHATIAN!</b>\n');
}

reminderLines.push('---');
reminderLines.push(`📊 Total Proyek Aktif: ${activeProjects.length}`);
reminderLines.push('\nGunakan /summary untuk laporan lengkap.');

const fullText = reminderLines.join('\n');
const MAX_LEN = 4000;
const messages = [];
if (fullText.length <= MAX_LEN) {
  messages.push(fullText);
} else {
  let remaining = fullText;
  while (remaining.length > 0) {
    let chunk = remaining.substring(0, MAX_LEN);
    const lb = chunk.lastIndexOf('\n\n');
    if (lb > MAX_LEN * 0.5) chunk = remaining.substring(0, lb + 2);
    messages.push(chunk);
    remaining = remaining.substring(chunk.length);
  }
}

return messages.map(text => ({ json: { text } }));
